import React from "react";

export default function ModalConfig({ open, close, children }) {
  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        backgroundColor: "rgba(0, 0, 0, 0.5)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <div className="bg-white w-[90%] max-w-md h-90 relative">
        <button className="absolute top-3 right-3">X</button>
        {children}
      </div>
    </div>
  );
}
